import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Оновлення Fabric","description":"Покрокова інструкція з оновлення Fabric.","frontmatter":{"title":"Оновлення Fabric","description":"Покрокова інструкція з оновлення Fabric.","authors":["IMB11","modmuss50"],"search":false,"files":[]},"headers":[],"relativePath":"uk_ua/1.20.4/players/updating-fabric.md","filePath":"versions/1.20.4/translated/uk_ua/players/updating-fabric.md","lastUpdated":1739538073000}`);var c={name:`uk_ua/1.20.4/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Оновлення Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Оновлення Fabric”">​</a></h1><p>Ця інструкція допоможе вам оновити Fabric для офіційного лаунчера Minecraft.</p><p>Для неофіційних лаунчерів слід ознайомитися з їх документацією.</p><p>Процес оновлення Fabric дуже схожий на процес встановлення Fabric, тому частина цього посібника буде такою самою, як інструція <a href="./installing-fabric">Встановлення Fabric</a>.</p><h2 id="чому-я-маю-оновлювати-fabric-loader" tabindex="-1">Чому я маю оновлювати Fabric Loader? <a class="header-anchor" href="#чому-я-маю-оновлювати-fabric-loader" aria-label="Permalink to “Чому я маю оновлювати Fabric Loader?”">​</a></h2><p>Нові моди можуть потребувати новішу версію Fabric Loader для роботи, тому важливо мати актуальну версію, щоб мати можливість використовувати найновіші моди.</p><p>Для неофіційних лаунчерів слід ознайомитися з їх документацією.</p><h2 id="_1-завантаження-інсталятора-fabric" tabindex="-1">1. Завантаження інсталятора Fabric <a class="header-anchor" href="#_1-завантаження-інсталятора-fabric" aria-label="Permalink to “1. Завантаження інсталятора Fabric”">​</a></h2><p>Ви можете завантажити Інсталятор Fabric з <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">вебсайту Fabric</a>.</p><p>Якщо ви користуєтеся Windows, завантажте версію <code>.exe</code> (<code>Download For Windows</code>), оскільки для цього не потрібно інсталювати Java у вашій системі. Натомість він використовує Java, яка постачається з офіційним лаунчером.</p><p>Для macOS та Linux вам слід завантажити <code>jar</code> версію. Іноді перед цим кроком потрібно встановити Java.</p><h2 id="_2-запуск-інсталятора-fabric" tabindex="-1">2. Запуск інсталятора Fabric <a class="header-anchor" href="#_2-запуск-інсталятора-fabric" aria-label="Permalink to “2. Запуск інсталятора Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Спочатку закрийте Minecraft та його лаунчер перед встановленням.</p></div><details class="details custom-block"><summary>Інформація для користувачів MacOS</summary><p>У macOS вам може знадобитися клацнути правою кнопкою миші файл <code>.jar</code> у каталозі завантажень і натиснути <code>Відкрити</code>, щоб запустити його.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Інсталятор Fabric із виділеним пунктом «Встановити»" loading="lazy"></p><p>Коли вас запитають «Ви впевнені, що хочете відкрити?», знову натисніть <code>Відкрити</code>.</p></details><p>Відкривши інсталятор, ви повинні побачити такий екран:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Інсталятор Fabric із виділеним пунктом «Встановити»" loading="lazy"></p><p>Щоб установити Fabric, просто виберіть свою версію гри зі спадного меню та натисніть <code>Встановити</code>.</p><p>Щоб оновити Fabric, переконайтеся що версія гри та версія завантажувача правильні, а потім натисніть <code>Встановити</code>.</p><p><strong>Під час запуску інсталятора обов&#39;язково зніміть прапорець «Створити профіль», інакше буде створено новий профіль, який у цьому випадку нам не потрібен.</strong></p><h2 id="_3-відкриите-профіль-в-лаунчері-minecraft" tabindex="-1">3. Відкрийте профіль в лаунчері Minecraft <a class="header-anchor" href="#_3-відкриите-профіль-в-лаунчері-minecraft" aria-label="Permalink to “3. Відкрийте профіль в лаунчері Minecraft”">​</a></h2><p>Після завершення встановлення ви можете відкрити лаунчер Minecraft і перейти на вкладку <code>Встановлення</code>. Ви повинні перейти до свого профілю Fabric і відкрити екран редагування.</p><p>Замініть версію новою версією Fabric Loader, яку ви щойно встановили, і натисніть <code>Зберегти</code>.</p><p><img src="/assets/players/updating-fabric.png" alt="Оновлення версії Fabric Loader у лаунчері Minecraft" loading="lazy"></p><h2 id="_4-готово" tabindex="-1">4. Готово! <a class="header-anchor" href="#_4-готово" aria-label="Permalink to “4. Готово!”">​</a></h2><p>Виконавши дані кроки, ви можете повернутися на вкладку <code>Грати</code>, вибрати профіль Fabric зі спадного меню в нижньому лівому куті та натиснути кнопку <code>Грати</code>!</p><p>Якщо під час виконання цієї інструкції у вас виникнуть проблеми, ви можете звернутися за допомогою в <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Діскорд сервері Fabric</a> в каналі <code>#player-support</code>.</p>`,26)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};